const d = $input.first().json;
const totalRevenue = parseFloat(d.totalRevenue) || 0;
const totalCost = parseFloat(d.totalCost) || 0;
const unitsSold = parseInt(d.unitsSold) || 0;
const consumerCaptures = parseInt(d.consumerCaptures) || 0;

const roi = totalCost > 0 ? ((totalRevenue - totalCost) / totalCost * 100).toFixed(1) : '0';
const revenuePerUnit = unitsSold > 0 ? (totalRevenue / unitsSold).toFixed(2) : '0';
const daysActive = parseInt(d.daysActive) || 4;
const dailyRevenue = daysActive > 0 ? (totalRevenue / daysActive).toFixed(2) : '0';

return [{ json: {
  ...d,
  totalRevenue, totalCost, unitsSold, consumerCaptures,
  roi: parseFloat(roi),
  revenuePerUnit: parseFloat(revenuePerUnit),
  dailyRevenue: parseFloat(dailyRevenue),
  eventComplete: true,
  phase: 8,
  closedAt: new Date().toISOString()
} }];

const d = $input.first().json;
let report = '';
try { report = d.content[0].text; } catch(e) { report = 'Report generation failed.'; }
const brandData = $('Aggregate Event Data').first().json;
return [{ json: { ...brandData, executiveReport: report } }];
